201→export default function FixtureRenderer({ fixtures }) {
202→  return (
203→    <g className="fixtures">
204→      {fixtures.map(fixture => {
205→        const outline = fixtureOutline(fixture);
206→        const points = outline.map(p => `${p.x},${p.y}`).join(' ');
207→        const gradFill = `url(#grad-${fixture.fixtureType})`;
208→        return (
209→          <g key={fixture.id} filter="url(#fixture-shadow)">
210→            <polygon
211→              data-id={fixture.id}
212→              data-type="fixture"
213→              points={points}
214→              fill={gradFill}
215→              stroke="#8A7D6B"
216→              strokeWidth={1.5}
217→              vectorEffect="non-scaling-stroke"
218→            />
219→            <FixtureDetails fixture={fixture} />
220→          </g>
221→        );
222→      })}
223→    </g>
224→  );
225→}
